DROP TABLE IF EXISTS `sub_renewals`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `sub_renewals` (
  `seq` int(9) NOT NULL AUTO_INCREMENT,
  `id` int(9) NOT NULL,
  `first_issue` int(6) NOT NULL,
  `last_issue` int(6) NOT NULL,
  `years` int(1) DEFAULT NULL,
  `method` enum('P','Q','C','F') DEFAULT 'Q',
  `date` datetime DEFAULT NULL,
  PRIMARY KEY (`seq`),
  KEY `id` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2891 DEFAULT CHARSET=latin1 COMMENT='sub_renewals';
