DROP TABLE IF EXISTS `sub_subscribers`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `sub_subscribers` (
  `id` int(9) NOT NULL AUTO_INCREMENT,
  `renewal_id` varchar(10) DEFAULT NULL,
  `email` varchar(100) DEFAULT NULL,
  `title` varchar(10) DEFAULT NULL,
  `forename` varchar(60) DEFAULT NULL,
  `surname` varchar(60) DEFAULT NULL,
  `company` varchar(100) DEFAULT NULL,
  `address1` varchar(80) DEFAULT NULL,
  `address2` varchar(80) DEFAULT NULL,
  `city` varchar(80) DEFAULT NULL,
  `country` int(3) DEFAULT '0',
  `region` varchar(80) DEFAULT NULL,
  `pcode` varchar(10) DEFAULT NULL,
  `phone` varchar(20) DEFAULT NULL,
  `mobile` varchar(20) DEFAULT NULL,
  `notes` mediumtext,
  `renewal` enum('Y','N') DEFAULT NULL,
  `years` int(1) DEFAULT '1',
  `first_issue` int(6) DEFAULT NULL,
  `last_issue` int(6) DEFAULT NULL,
  `date_subscribed` int(10) DEFAULT '0',
  `date_renewed` int(10) DEFAULT '0',
  `method` enum('P','Q','C','F') DEFAULT NULL,
  `free` enum('Y','N') DEFAULT 'N',
  `paymate_response` varchar(2) DEFAULT NULL,
  `paymate_txid` bigint(11) NOT NULL,
  `paymate_text` mediumtext,
  `admin_notes` mediumtext,
  `gift` enum('Y','N') DEFAULT 'N',
  `email2` varchar(100) DEFAULT NULL,
  `name2` varchar(60) DEFAULT NULL,
  `address12` varchar(80) DEFAULT NULL,
  `address22` varchar(80) DEFAULT NULL,
  `city2` varchar(80) DEFAULT NULL,
  `country2` int(3) DEFAULT '0',
  `region2` varchar(80) DEFAULT NULL,
  `pcode2` varchar(10) DEFAULT NULL,
  `phone2` varchar(20) DEFAULT NULL,
  `mobile2` varchar(20) DEFAULT NULL,
  `address_search` varchar(200) DEFAULT NULL,
  `DVD` enum('Y','N') DEFAULT 'N',
  PRIMARY KEY (`id`),
  KEY `email` (`email`),
  KEY `renewal_id` (`renewal_id`),
  KEY `surname` (`surname`)
) ENGINE=InnoDB AUTO_INCREMENT=11166 DEFAULT CHARSET=latin1 COMMENT='sub_subscribers';
/*!40101 SET character_set_client = @saved_cs_client */;

